  zbuf_append(buf, "]},\"verificationCommands\":[");
  if (ok) {
    zbuf_append(buf, "{\"purpose\":\"source-check\",\"required\":true,\"argv\":[\"zero\",\"check\",\"--json\""); if (target_arg) { zbuf_append(buf, ",\"--target\","); agent_json_string(buf, target); } if (profile_arg) { zbuf_append(buf, ",\"--profile\","); agent_json_string(buf, profile); } zbuf_append(buf, ","); agent_json_string(buf, path ? path : ""); zbuf_append(buf, "]}");
    zbuf_append(buf, ",{\"purpose\":\"graph-check\",\"required\":true,\"argv\":[\"zero\",\"graph\",\"check\",\"--json\""); if (target_arg) { zbuf_append(buf, ",\"--target\","); agent_json_string(buf, target); } if (profile_arg) { zbuf_append(buf, ",\"--profile\","); agent_json_string(buf, profile); } zbuf_append(buf, ","); agent_json_string(buf, path ? path : ""); zbuf_append(buf, "]}");
  }
