static const char *agent_graph_patch_failure_class(const char *code) { return agent_code_is(code, '2') ? "stale-graph" : agent_code_is(code, '5') ? "precondition-failed" : agent_code_is(code, '4') ? "missing-graph-target" : agent_code_is(code, '6') ? "invalid-result-graph" : agent_code_is(code, '3') ? "invalid-patch-value" : "invalid-patch"; }
static const char *agent_graph_patch_retry_strategy(const char *code) { return agent_code_is(code, '2') ? "rerun graph dump and rebuild patch against current graph hash" : agent_code_is(code, '5') ? "use operations[].retryCommands graph-impact for the failed node, then rebuild patch with current impact guards" : agent_code_is(code, '3') ? "reinspect the graph contract and rebuild the patch with valid typed values" : agent_code_is(code, '1') ? "reinspect the graph patch contract and rebuild syntactically valid patch input" : "repair patch input before retry"; }
static const char *agent_graph_patch_failure_phase(const char *code) { return agent_code_is(code, '2') ? "inspect" : agent_code_is(code, '5') || agent_code_is(code, '4') || agent_code_is(code, '3') ? "patch" : agent_code_is(code, '6') ? "validate" : "parse"; }

static void agent_graph_patch_retry_commands_json(ZBuf *buf, const char *code, const char *artifact, bool target_arg, const char *target, bool profile_arg, const char *profile) { zbuf_append(buf, "["); if (agent_code_is(code, '2')) { zbuf_append(buf, "{\"purpose\":\"graph-dump\",\"required\":true,\"argv\":[\"zero\",\"graph\",\"dump\",\"--json\""); if (target_arg) { zbuf_append(buf, ",\"--target\","); agent_json_string(buf, target); } if (profile_arg) { zbuf_append(buf, ",\"--profile\","); agent_json_string(buf, profile); } zbuf_append(buf, ","); agent_json_string(buf, artifact); zbuf_append(buf, "]}"); } else if (agent_code_is(code, '5') || agent_code_is(code, '4') || agent_code_is(code, '3') || agent_code_is(code, '1')) { zbuf_append(buf, "{\"purpose\":\"graph-inspect\",\"required\":true,\"argv\":[\"zero\",\"graph\",\"inspect\",\"--json\""); if (target_arg) { zbuf_append(buf, ",\"--target\","); agent_json_string(buf, target); } if (profile_arg) { zbuf_append(buf, ",\"--profile\","); agent_json_string(buf, profile); } zbuf_append(buf, ","); agent_json_string(buf, artifact); zbuf_append(buf, "]}"); } zbuf_append(buf, "]"); }
static void agent_graph_patch_source_result_fields_json(ZBuf *buf) { zbuf_append(buf, ",\"resultFields\":[\"ok\",\"diagnostics\",\"agentCommand.verificationCommands\"]"); } static void agent_graph_patch_graph_result_fields_json(ZBuf *buf) { zbuf_append(buf, ",\"resultFields\":[\"ok\",\"diagnostics\",\"graphHash\",\"agentCommand.verificationCommands\"]"); } static void agent_graph_patch_artifact_result_fields_json(ZBuf *buf) { zbuf_append(buf, ",\"resultFields\":[\"ok\",\"graphHash\",\"validation.ok\",\"agentCommand.verificationCommands\"]"); }
static void agent_graph_patch_phase_audit_json(ZBuf *buf, const char *code, bool ok, bool saved) { const char *failed = ok ? "" : agent_graph_patch_failure_phase(code); bool failed_inspect = failed[0] == 'i' || (failed[0] == 'p' && failed[1] == 'r'); bool failed_validate = failed[0] == 'v'; bool inspect_ok = ok || (failed[0] && !failed_inspect); bool patch_ok = ok || failed_validate; zbuf_append(buf, ",\"phaseAudit\":{\"inspect\":{\"ok\":"); zbuf_append(buf, inspect_ok ? "true" : "false"); zbuf_append(buf, ",\"proof\":\"originalGraphHash\"},\"patch\":{\"ok\":"); zbuf_append(buf, patch_ok ? "true" : "false"); zbuf_append(buf, ",\"proof\":\"operations\"},\"validate\":{\"ok\":"); zbuf_append(buf, ok ? "true" : "false"); zbuf_append(buf, ",\"proof\":\"patchedGraphHash\"},\"save\":{\"ok\":"); zbuf_append(buf, saved ? "true" : "false"); zbuf_append(buf, ",\"proof\":\"rollback.savedPath\"},\"verify\":{\"status\":"); agent_json_string(buf, ok && saved ? "scheduled" : "not-scheduled"); zbuf_append(buf, ",\"proof\":\"verificationCommands\"}}"); }
static void agent_graph_patch_proof_ledger_json(ZBuf *buf, const char *code, bool ok, bool saved, bool saved_source) { const char *failed = ok ? "" : agent_graph_patch_failure_phase(code); bool failed_inspect = failed[0] == 'i' || (failed[0] == 'p' && failed[1] == 'r'); bool failed_validate = failed[0] == 'v'; bool inspect_ok = ok || (failed[0] && !failed_inspect); bool patch_ok = ok || failed_validate; zbuf_append(buf, ",\"proofLedger\":{\"schemaVersion\":1,\"kind\":\"graph-patch-proof-ledger\",\"phaseOrder\":[\"inspect\",\"patch\",\"validate\",\"save\",\"verify\",\"rollback\"],\"phases\":["); zbuf_append(buf, "{\"phase\":\"inspect\",\"status\":"); agent_json_string(buf, inspect_ok ? "passed" : "failed"); zbuf_append(buf, ",\"evidenceFields\":[\"agentTransaction.originalGraphHash\",\"agentTransaction.command.argv\"]}"); zbuf_append(buf, ",{\"phase\":\"patch\",\"status\":"); agent_json_string(buf, patch_ok ? "passed" : "failed"); zbuf_append(buf, ",\"evidenceFields\":[\"operations[]\",\"agentTransaction.operationCount\",\"agentTransaction.patchContract\"]}"); zbuf_append(buf, ",{\"phase\":\"validate\",\"status\":"); agent_json_string(buf, ok ? "passed" : failed_validate ? "failed" : "not-scheduled"); zbuf_append(buf, ",\"evidenceFields\":[\"agentTransaction.patchedGraphHash\",\"phaseAudit.validate.proof\"]}"); zbuf_append(buf, ",{\"phase\":\"save\",\"status\":"); agent_json_string(buf, saved ? "passed" : "not-scheduled"); zbuf_append(buf, ",\"evidenceFields\":[\"agentTransaction.rollback.savedKind\",\"agentTransaction.rollback.savedPath\",\"saved.graphHash\",\"saveProof.savedGraphHash\",\"saveProof.comparedGraphHash\"]}"); zbuf_append(buf, ",{\"phase\":\"verify\",\"status\":"); agent_json_string(buf, ok && saved ? "scheduled" : "not-scheduled"); zbuf_append(buf, ",\"evidenceFields\":[\"agentTransaction.verificationCommands[].purpose\",\"agentTransaction.verificationCommands[].argv\",\"agentTransaction.verificationCommands[].resultFields\"],\"requiredPurposes\":["); if (ok && saved) zbuf_append(buf, saved_source ? "\"source-check\",\"graph-check\"" : "\"artifact-validate\",\"graph-check\""); zbuf_append(buf, "]}"); zbuf_append(buf, ",{\"phase\":\"rollback\",\"status\":"); agent_json_string(buf, saved ? "available" : "not-available"); zbuf_append(buf, ",\"evidenceFields\":[\"agentTransaction.rollback.actions[]\",\"agentTransaction.rollback.verificationCommands[].purpose\",\"agentTransaction.rollback.verificationCommands[].argv\",\"agentTransaction.rollback.verificationCommands[].resultFields\"],\"requiredPurposes\":["); if (ok && saved) zbuf_append(buf, saved_source ? "\"rollback-source-check\",\"rollback-graph-check\"" : "\"rollback-artifact-validate\",\"rollback-graph-check\""); zbuf_append(buf, "]}],\"failureCode\":"); if (ok) zbuf_append(buf, "null"); else agent_json_string(buf, code); zbuf_append(buf, ",\"verifiedBy\":\"agentTransaction.verificationCommands\"}"); }
