    zbuf_append(buf, ",\"phase\":"); agent_json_string(buf, agent_graph_patch_failure_phase(diagnostic_code));
    zbuf_append(buf, ",\"retryable\":"); zbuf_append(buf, (agent_code_is(diagnostic_code, '1') || agent_code_is(diagnostic_code, '2') || agent_code_is(diagnostic_code, '3') || agent_code_is(diagnostic_code, '4') || agent_code_is(diagnostic_code, '5')) ? "true" : "false"); zbuf_append(buf, ",\"retryStrategy\":"); agent_json_string(buf, agent_graph_patch_retry_strategy(diagnostic_code));
